insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('23719', 'ga.ding-ga.ding', 'gading-gading', '', '', '["Nomina","Arkais"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"ark","nama":"Arkais","tipe":"kelas_kata"}],"definisi":"dua orang anak laki-laki yang mengipasi pengantin","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('23708', 'ga.ding', 'gading', '', '', '["Nomina","Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"taring panjang dan tajam pada binatang (gajah, walrus) yang berguna untuk menggali atau sebagai senjata","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"tulang keras putih dan bersih dari gading","contoh":[{"nomor":2,"teks":"keris berhulu --"}]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"(warna) putih kekuning-kuningan seperti gading","contoh":[]}]', '{"text":"[Jawa Kuno gaḍiṅ ''gading gajah; gading'']","languages":["Jawa Kuno"]}', '["bergading","menggading"]', '["gading-gading roda"]', '["bagai tanduk bersendi gading","harimau mati meninggalkan belang, gajah mati meninggalkan gading","harimau mati meninggalkan belang, gajah mati meninggalkan gading, orang mati meninggalkan nama","manusia mati meninggalkan nama (harimau mati meninggalkan belang, gajah mati meninggalkan gading)","pucuk leban gading gajah, bekerja segan mati gagah","semahal-mahal gading, kalau patah, tiada berguna","sudah dapat gading bertuah, tanduk tiada berguna lagi","tak ada gading yang tak retak","telah dapat gading bertuah, terbuang tanduk kerbau mati"]', '[]', '[{"peribahasa":"bagai tanduk bersendi gading","makna":"Peribahasa ini menggambarkan suatu keadaan yang tidak serasi atau tidak sepadan. Tanduk yang kasar dan gading yang halus tidak cocok jika disatukan, melambangkan ketidakcocokan dalam hubungan atau perpaduan yang tidak harmonis antara dua hal yang berbeda sifatnya."},{"peribahasa":"harimau mati meninggalkan belang, gajah mati meninggalkan gading","makna":"Ungkapan ini memiliki makna bahwa setiap makhluk hidup, terutama yang memiliki keistimewaan, akan meninggalkan ciri khas atau warisan setelah kematiannya. Harimau dikenal dengan belangnya, gajah dengan gadingnya, yang melambangkan bahwa seseorang akan dikenang berdasarkan jasa, karya, atau sifat baik yang ditinggalkannya."},{"peribahasa":"harimau mati meninggalkan belang, gajah mati meninggalkan gading, orang mati meninggalkan nama","makna":"Peribahasa ini adalah pengembangan dari peribahasa sebelumnya, yang secara eksplisit menyatakan bahwa manusia akan dikenang berdasarkan nama baik atau buruk yang mereka ukir selama hidup. Ini menekankan pentingnya berbuat kebaikan dan meninggalkan warisan yang positif bagi generasi mendatang."},{"peribahasa":"manusia mati meninggalkan nama (harimau mati meninggalkan belang, gajah mati meninggalkan gading)","makna":"Sama seperti peribahasa sebelumnya, ini adalah penekanan bahwa warisan terpenting yang ditinggalkan manusia bukanlah harta benda, melainkan reputasi dan nama baik yang akan dikenang sepanjang masa. Ini adalah dorongan untuk hidup bermakna dan berbuat kebajikan."},{"peribahasa":"pucuk leban gading gajah, bekerja segan mati gagah","makna":"Peribahasa ini menggambarkan seseorang yang malas bekerja atau berusaha, namun ingin terlihat gagah, berani, atau terhormat. Ini adalah sindiran bagi orang yang hanya ingin menikmati hasil tanpa mau berjuang, atau yang hanya mementingkan penampilan tanpa substansi."},{"peribahasa":"semahal-mahal gading, kalau patah, tiada berguna","makna":"Ungkapan ini mengajarkan bahwa betapapun berharganya sesuatu, jika sudah rusak atau tidak berfungsi lagi, maka nilainya akan hilang. Ini berlaku untuk benda maupun kemampuan atau kedudukan seseorang; jika sudah tidak dapat dimanfaatkan, maka tidak ada gunanya lagi."},{"peribahasa":"sudah dapat gading bertuah, tanduk tiada berguna lagi","makna":"Peribahasa ini menggambarkan situasi di mana seseorang telah mendapatkan sesuatu yang jauh lebih baik, berharga, atau menguntungkan, sehingga apa yang sebelumnya dianggap berharga menjadi tidak relevan atau tidak dibutuhkan lagi. Ini adalah metafora untuk peningkatan status atau keberuntungan."},{"peribahasa":"tak ada gading yang tak retak","makna":"Makna dari peribahasa ini adalah bahwa tidak ada sesuatu pun di dunia ini yang sempurna. Setiap orang atau setiap hal, betapapun baik atau indahnya, pasti memiliki kekurangan, kelemahan, atau cacat. Ini mengajarkan sikap toleransi dan penerimaan terhadap ketidaksempurnaan."},{"peribahasa":"telah dapat gading bertuah, terbuang tanduk kerbau mati","makna":"Sama seperti peribahasa \"sudah dapat gading bertuah, tanduk tiada berguna lagi\", ungkapan ini menegaskan bahwa ketika seseorang telah memperoleh sesuatu yang sangat berharga atau menguntungkan, maka hal-hal yang sebelumnya dianggap penting atau berguna akan ditinggalkan atau tidak lagi dihargai."}]');
