insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('23720', 'ga.dis', 'gadis', '', '', '["Nomina","Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"anak perempuan yang sudah akil balig; anak dara","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"anak perempuan yang belum kawin; perawan","contoh":[]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"binatang yang belum beranak atau bertelur; dara","contoh":[{"nomor":2,"teks":"ayam --"},{"nomor":4,"teks":"lembu --"}]}]', null, '["kegadis-gadisan","kegadisan","menggadis"]', '["gadis besar","gadis blasteran","gadis kecil","gadis pemerah","gadis sampul","gadis tanggung","gadis taruhan","gadis tua"]', '["bagai ayam gadis bertelur","bagai gadis jolong bersubang","malu-malu kucing, bujang dengan gadis","seperti gadis jolong bersubang, bujang jolong bekerja","seperti gadis sudah berlaki"]', '[]', '[{"peribahasa":"bagai ayam gadis bertelur","makna":"Peribahasa ini menggambarkan seseorang yang baru pertama kali melakukan sesuatu, sehingga ia merasa canggung, malu, atau tidak percaya diri. Ini melukiskan pengalaman awal yang penuh dengan keraguan dan ketidakpastian."},{"peribahasa":"bagai gadis jolong bersubang","makna":"Ungkapan ini melukiskan sikap seseorang yang baru pertama kali mendapatkan sesuatu yang baru atau berharga, sehingga ia merasa bangga, canggung, atau sedikit sombong. Ini adalah gambaran dari kegembiraan yang berlebihan atau kurangnya pengalaman dalam menghadapi hal baru."},{"peribahasa":"malu-malu kucing, bujang dengan gadis","makna":"Peribahasa ini menggambarkan sikap pura-pura malu atau jual mahal, padahal sebenarnya ada keinginan atau ketertarikan. Ini sering digunakan untuk melukiskan interaksi antara seorang pemuda dan pemudi yang saling tertarik namun enggan menunjukkan secara terang-terangan."},{"peribahasa":"seperti gadis jolong bersubang, bujang jolong bekerja","makna":"Ungkapan ini menggambarkan seseorang yang baru pertama kali mendapatkan sesuatu yang baru atau melakukan pekerjaan, sehingga ia merasa canggung, malu, atau sedikit sombong. Ini adalah gambaran dari kegembiraan yang berlebihan atau kurangnya pengalaman dalam menghadapi hal baru."},{"peribahasa":"seperti gadis sudah berlaki","makna":"Peribahasa ini menggambarkan seseorang yang sudah tidak perawan lagi atau sudah menikah. Ini adalah ungkapan yang merujuk pada perubahan status sosial dan pengalaman hidup seorang perempuan setelah menikah."}]');
