insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('23786', 'ga.gak', 'gagak', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"burung yang berbulu hitam, bentuk badannya besar, pemakan bangkai, dan suaranya keras〔Corvus macrorhynchos〕","contoh":[]}]', null, '[]', '["gagak banggai","gagak flores","gagak halmahera","gagak kelabu","gagak kepala cokelat","gagak orru","gagak rumah","gagak sulawesi"]', '["hitam, hitam gagak, putih, putih udang kapai (hitam, hitam bendi, putih, putih sadah)","ketika gagak putih, bangau hitam","menanti putih gagak hitam","selama gagak hitam, selama air hilir","seperti burung gagak pulang ke benua"]', '[]', '[{"peribahasa":"hitam, hitam gagak, putih, putih udang kapai (hitam, hitam bendi, putih, putih sadah)","makna":"Peribahasa ini menegaskan bahwa sifat atau warna asli sesuatu tidak akan berubah, meskipun dicampur atau diubah dengan hal lain. Ini melambangkan keteguhan karakter atau identitas yang tidak dapat dihilangkan, meskipun ada upaya untuk menyamarkannya."},{"peribahasa":"ketika gagak putih, bangau hitam","makna":"Ungkapan ini menggambarkan suatu kondisi yang sangat tidak mungkin terjadi atau mustahil. Ini adalah metafora untuk hal-hal yang bertentangan dengan kodrat atau kebiasaan alamiah, sehingga tidak akan pernah terwujud."},{"peribahasa":"menanti putih gagak hitam","makna":"Peribahasa ini melambangkan penantian yang sia-sia atau harapan yang tidak akan pernah terwujud. Ini merujuk pada menunggu sesuatu yang mustahil terjadi, seperti gagak hitam yang tidak akan pernah berubah menjadi putih."},{"peribahasa":"selama gagak hitam, selama air hilir","makna":"Ungkapan ini berarti selama-lamanya atau untuk waktu yang sangat panjang, bahkan abadi. Ini digunakan untuk menyatakan sesuatu yang akan terus berlangsung tanpa henti, seperti gagak yang selalu hitam dan air yang selalu mengalir ke hilir."},{"peribahasa":"seperti burung gagak pulang ke benua","makna":"Peribahasa ini menggambarkan seseorang yang kembali ke tempat asalnya atau ke kebiasaan lamanya setelah lama merantau atau mencoba hal baru. Meskipun telah melihat banyak hal, ia tetap kembali pada sifat atau lingkungan aslinya."}]');
