insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('23882', 'ga.jah-ga.jah.an', 'gajah-gajahan', '', 'gajah¹', '["Nomina","Klasik","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"kl","nama":"Klasik","tipe":"kelas_kata"}],"definisi":"permainan catur","contoh":[{"nomor":2,"teks":"main ~"}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"penyakit yang menyebabkan kaki membengkak menjadi besar; elefantiasis","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('23860', 'ga.jah', 'gajah', '', '', '["Nomina","Nomina","Nomina","kiasan"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"mamalia berbelalai, bergading, berkaki besar, berkulit tebal, berambut abu-abu, berdaun telinga lebar, terdapat di Asia dan Afrika〔Elephantidae〕","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"nama buah catur yang jalannya selalu menyerong (disebut juga menteri)","contoh":[]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"segala sesuatu yang berukuran besar","contoh":[{"nomor":2,"teks":"anak itu menangkap kupu-kupu --"}]}]', '{"text":"[Sanskerta गज gaja n m ''gajah'']","languages":["Sanskerta"]}', '["bergajah","gajah-gajahan","menggajah"]', '["gajah afrika","gajah asia","gajah baliku","gajah bara","gajah barat","gajah butang","gajah gambut","gajah guling","gajah hotong","gajah lalang","gajah menong","gajah menunggang","gajah menyusu","gajah mina","gajah oling","gajah talena","gajah tunggal","gajah uling","gajah laut"]', '["adat gajah terdorong","anjing menyalak di ekor (pantat) gajah","anjing menyalak di ekor gajah","asal ada sama di hati, gajah terantai boleh dilepaskan","bagai anai-anai diinjak gajah","bagai denai gajah lalu","bagai langau di ekor gajah","daging gajah sama dilapah, daging tuma sama dicecah","gajah berjuang sama gajah, pelanduk (kancil) mati di tengah-tengah","gajah derum di tengah rumah","gajah dikalahkan oleh pelanduk","gajah ditelan ular lidi","gajah lalu dibeli, kusa tidak terbeli","gajah lalu dibeli, rusa tidak terbeli","gajah mati karena gadingnya","gajah mati, tulang setimbun","gajah pengangkut lada, kuda pelejang bukit","gajah seekor, gembala dua","gajah terdorong karena gadingnya, harimau terlompat karena belangnya","harimau mati meninggalkan belang, gajah mati meninggalkan gading","harimau mati meninggalkan belang, gajah mati meninggalkan gading, orang mati meninggalkan nama","hati gajah sama dilapah, hati kuman (tungau) sama dicecah (dicecap)","hati gajah sama dilapah, hati tuma (tungau) sama dicecah","hitam-hitam gajah, putih-putih udang kepai","kuman di seberang lautan tampak, gajah di pelupuk mata tidak tampak","manusia mati meninggalkan nama (harimau mati meninggalkan belang, gajah mati meninggalkan gading)","masuk dalam kawanan gajah berdering","mati gajah tidak dapat belalainya, mati harimau tidak dapat belangnya","menangkap gajah liar itu dengan gajah juga","menguak-nguak bagai hidung gajah","pucuk leban gading gajah, bekerja segan mati gagah","semut dipijak tidak mati, gajah diarung bergelimpangan (semut terpijak tidak mati, alu tertarung patah tiga)","seperti ditempuh gajah lalu","seperti gajah dengan sengkelanya","seperti gajah masuk kampung","tebu masuk di mulut gajah","tebu setuntung masuk geraham gajah","terdorong gajah karena besarnya"]', '[]', '[{"peribahasa":"adat gajah terdorong","makna":"Peribahasa ini menggambarkan bahwa seseorang yang memiliki kedudukan tinggi, kekuasaan, atau kekayaan cenderung akan bertindak sesuai dengan statusnya, bahkan jika itu berarti melakukan hal-hal yang besar atau berani. Ini adalah cerminan dari pengaruh status terhadap perilaku."},{"peribahasa":"anjing menyalak di ekor (pantat) gajah","makna":"Ungkapan ini melukiskan tindakan seseorang yang lemah atau tidak berdaya yang mencoba menentang atau mengkritik pihak yang jauh lebih kuat dan berkuasa. Usaha tersebut dianggap sia-sia dan tidak akan memberikan dampak signifikan, seperti anjing yang menyalak pada gajah."},{"peribahasa":"anjing menyalak di ekor gajah","makna":"Sama seperti peribahasa sebelumnya, ini menggambarkan upaya yang tidak berarti dari pihak yang lemah untuk menentang atau mengganggu pihak yang kuat. Perlawanan tersebut tidak akan mampu menggoyahkan kedudukan atau kekuatan pihak yang lebih besar."},{"peribahasa":"asal ada sama di hati, gajah terantai boleh dilepaskan","makna":"Peribahasa ini menekankan pentingnya kesepahaman dan keikhlasan dalam suatu hubungan. Jika sudah ada kesamaan hati dan niat baik, maka segala bentuk ikatan atau batasan formal dapat dikesampingkan, bahkan hal yang besar sekalipun dapat dilepaskan demi kebersamaan."},{"peribahasa":"bagai anai-anai diinjak gajah","makna":"Ungkapan ini menggambarkan kehancuran total atau kekalahan mutlak yang dialami oleh pihak yang sangat lemah ketika berhadapan dengan kekuatan yang jauh lebih besar. Ini melambangkan ketidakberdayaan dan ketidakmampuan untuk melawan."},{"peribahasa":"bagai denai gajah lalu","makna":"Peribahasa ini melukiskan suatu kejadian atau peristiwa besar yang meninggalkan dampak atau jejak yang sangat jelas dan tidak dapat disembunyikan. Seperti jejak gajah yang besar dan mudah terlihat, demikian pula dampak dari peristiwa penting akan sulit dihilangkan."},{"peribahasa":"bagai langau di ekor gajah","makna":"Ungkapan ini menggambarkan seseorang yang selalu mengikuti atau bergantung pada orang yang lebih berkuasa atau berpengaruh, dengan harapan mendapatkan keuntungan atau perlindungan. Namun, keberadaannya tidak terlalu berarti bagi pihak yang diikuti."},{"peribahasa":"daging gajah sama dilapah, daging tuma sama dicecah","makna":"Peribahasa ini mengajarkan prinsip keadilan dan kebersamaan dalam pembagian hasil, baik itu keuntungan besar maupun kecil. Segala sesuatu harus dibagi secara merata dan adil, tanpa memandang besar kecilnya nilai, demi menjaga kerukunan dan keharmonisan."},{"peribahasa":"gajah berjuang sama gajah, pelanduk (kancil) mati di tengah-tengah","makna":"Ungkapan ini menggambarkan bahwa dalam konflik atau persaingan antara pihak-pihak yang kuat dan berkuasa, pihak yang lemah dan tidak terlibat sering kali menjadi korban atau menanggung akibatnya. Ini adalah peringatan bagi pihak yang tidak berdaya untuk menjauhi konflik besar."},{"peribahasa":"gajah derum di tengah rumah","makna":"Peribahasa ini melukiskan suatu masalah besar atau peristiwa penting yang terjadi di dalam lingkungan keluarga atau komunitas, yang dampaknya sangat terasa dan tidak dapat diabaikan. Kehadiran masalah tersebut sangat mengganggu dan menarik perhatian semua pihak."},{"peribahasa":"gajah dikalahkan oleh pelanduk","makna":"Ungkapan ini menggambarkan bahwa kecerdikan dan strategi dapat mengalahkan kekuatan fisik atau ukuran yang besar. Meskipun secara fisik lebih kecil, pelanduk yang cerdik mampu mengalahkan gajah yang besar, menunjukkan bahwa akal budi lebih unggul dari kekuatan semata."},{"peribahasa":"gajah ditelan ular lidi","makna":"Peribahasa ini menggambarkan suatu kejadian yang sangat tidak masuk akal atau mustahil terjadi, di mana pihak yang sangat kecil atau lemah mampu mengalahkan atau menaklukkan pihak yang jauh lebih besar dan kuat. Ini adalah metafora untuk hal yang di luar nalar."},{"peribahasa":"gajah lalu dibeli, kusa tidak terbeli","makna":"Ungkapan ini menyindir seseorang yang mampu membeli atau mendapatkan barang-barang mewah dan mahal, namun tidak mampu membeli atau mendapatkan hal-hal kecil yang sebenarnya lebih penting atau mendasar. Ini menunjukkan prioritas yang salah atau ketidakmampuan dalam mengelola keuangan."},{"peribahasa":"gajah lalu dibeli, rusa tidak terbeli","makna":"Sama seperti peribahasa sebelumnya, ini menggambarkan seseorang yang mampu membeli barang-barang besar dan mahal, tetapi tidak mampu membeli barang-barang kecil yang sebenarnya lebih penting atau mendasar. Ini adalah kritik terhadap pemborosan atau ketidakmampuan dalam mengatur prioritas."},{"peribahasa":"gajah mati karena gadingnya","makna":"Peribahasa ini mengajarkan bahwa kelebihan atau keistimewaan yang dimiliki seseorang, jika tidak dikelola dengan baik, justru dapat menjadi penyebab kehancuran atau kemalangannya. Gading yang berharga pada gajah justru menjadi incaran pemburu yang menyebabkan kematiannya."},{"peribahasa":"gajah mati, tulang setimbun","makna":"Ungkapan ini memiliki makna bahwa orang besar atau orang yang memiliki pengaruh, meskipun telah meninggal dunia, akan tetap meninggalkan warisan yang besar, baik itu berupa karya, nama baik, maupun dampak yang signifikan bagi masyarakat. Warisannya akan terus dikenang dan bermanfaat."},{"peribahasa":"gajah pengangkut lada, kuda pelejang bukit","makna":"Peribahasa ini menggambarkan pembagian tugas atau peran yang sesuai dengan kemampuan dan keahlian masing-masing individu. Setiap orang memiliki kelebihan dan kekurangan, sehingga penting untuk menempatkan seseorang pada posisi yang tepat agar pekerjaan dapat berjalan efektif."},{"peribahasa":"gajah seekor, gembala dua","makna":"Ungkapan ini melukiskan situasi di mana satu pekerjaan atau satu objek dikelola oleh terlalu banyak orang, sehingga menyebabkan kebingungan, tumpang tindih, atau ketidakefisienan. Ini adalah kritik terhadap manajemen yang buruk atau kurangnya koordinasi."},{"peribahasa":"gajah terdorong karena gadingnya, harimau terlompat karena belangnya","makna":"Peribahasa ini mengajarkan bahwa setiap makhluk atau individu memiliki ciri khas atau kelebihan yang menjadi identitasnya. Kelebihan tersebut dapat menjadi pendorong untuk bertindak atau menjadi penyebab suatu peristiwa, baik positif maupun negatif."},{"peribahasa":"harimau mati meninggalkan belang, gajah mati meninggalkan gading","makna":"Ungkapan ini memiliki makna bahwa setiap makhluk hidup, terutama yang memiliki keistimewaan, akan meninggalkan ciri khas atau warisan setelah kematiannya. Harimau dikenal dengan belangnya, gajah dengan gadingnya, yang melambangkan bahwa seseorang akan dikenang berdasarkan jasa, karya, atau sifat baik yang ditinggalkannya."},{"peribahasa":"harimau mati meninggalkan belang, gajah mati meninggalkan gading, orang mati meninggalkan nama","makna":"Peribahasa ini adalah pengembangan dari peribahasa sebelumnya, yang secara eksplisit menyatakan bahwa manusia akan dikenang berdasarkan nama baik atau buruk yang mereka ukir selama hidup. Ini menekankan pentingnya berbuat kebaikan dan meninggalkan warisan yang positif bagi generasi mendatang."},{"peribahasa":"hati gajah sama dilapah, hati kuman (tungau) sama dicecah (dicecap)","makna":"Peribahasa ini mengajarkan prinsip keadilan dan kebersamaan dalam pembagian hasil, baik itu keuntungan besar maupun kecil. Segala sesuatu harus dibagi secara merata dan adil, tanpa memandang besar kecilnya nilai, demi menjaga kerukunan dan keharmonisan."},{"peribahasa":"hati gajah sama dilapah, hati tuma (tungau) sama dicecah","makna":"Sama seperti peribahasa sebelumnya, ini menekankan pentingnya keadilan dalam pembagian. Baik keuntungan besar maupun kecil, semuanya harus dibagi secara adil dan merata, menunjukkan semangat kebersamaan dan menghindari keserakahan."},{"peribahasa":"hitam-hitam gajah, putih-putih udang kepai","makna":"Peribahasa ini menegaskan bahwa sifat atau warna asli sesuatu tidak akan berubah, meskipun dicampur atau diubah dengan hal lain. Ini melambangkan keteguhan karakter atau identitas yang tidak dapat dihilangkan, meskipun ada upaya untuk menyamarkannya."},{"peribahasa":"kuman di seberang lautan tampak, gajah di pelupuk mata tidak tampak","makna":"Ungkapan ini mengkritik sikap seseorang yang mudah melihat kesalahan atau kekurangan kecil pada orang lain, namun tidak mampu melihat kesalahan atau kekurangan besar pada dirinya sendiri. Ini adalah sindiran bagi orang yang tidak introspektif dan cenderung menghakimi."},{"peribahasa":"manusia mati meninggalkan nama (harimau mati meninggalkan belang, gajah mati meninggalkan gading)","makna":"Sama seperti peribahasa sebelumnya, ini adalah penekanan bahwa warisan terpenting yang ditinggalkan manusia bukanlah harta benda, melainkan reputasi dan nama baik yang akan dikenang sepanjang masa. Ini adalah dorongan untuk hidup bermakna dan berbuat kebajikan."},{"peribahasa":"masuk dalam kawanan gajah berdering","makna":"Peribahasa ini menggambarkan seseorang yang bergabung atau terlibat dalam kelompok orang-orang besar, berkuasa, atau berpengaruh. Ini bisa berarti mendapatkan keuntungan dari asosiasi tersebut, atau justru terancam oleh kekuatan yang lebih besar."},{"peribahasa":"mati gajah tidak dapat belalainya, mati harimau tidak dapat belangnya","makna":"Ungkapan ini memiliki makna bahwa ketika seseorang yang memiliki keistimewaan atau kelebihan meninggal dunia, keistimewaan tersebut tidak dapat diwariskan atau diambil oleh orang lain. Ini menekankan keunikan dan ketidakgantian individu."},{"peribahasa":"menangkap gajah liar itu dengan gajah juga","makna":"Peribahasa ini mengajarkan bahwa untuk menghadapi atau mengatasi masalah besar atau musuh yang kuat, diperlukan kekuatan atau strategi yang sepadan. Tidak mungkin mengalahkan kekuatan besar dengan cara yang lemah atau tidak memadai."},{"peribahasa":"menguak-nguak bagai hidung gajah","makna":"Ungkapan ini menggambarkan seseorang yang berbicara dengan suara keras, sombong, atau angkuh, seolah-olah ingin menunjukkan kekuasaan atau kebesarannya. Ini adalah sindiran bagi orang yang suka membual atau meremehkan orang lain."},{"peribahasa":"pucuk leban gading gajah, bekerja segan mati gagah","makna":"Peribahasa ini menggambarkan seseorang yang malas bekerja atau berusaha, namun ingin terlihat gagah, berani, atau terhormat. Ini adalah sindiran bagi orang yang hanya ingin menikmati hasil tanpa mau berjuang, atau yang hanya mementingkan penampilan tanpa substansi."},{"peribahasa":"semut dipijak tidak mati, gajah diarung bergelimpangan (semut terpijak tidak mati, alu tertarung patah tiga)","makna":"Ungkapan ini melukiskan kebijaksanaan dan kehati-hatian seseorang dalam bertindak. Ia mampu menyelesaikan masalah tanpa menimbulkan kerugian bagi pihak yang lemah, namun juga mampu menghadapi tantangan besar dengan kekuatan yang luar biasa. Ini adalah gambaran dari pemimpin yang adil dan bijaksana."},{"peribahasa":"seperti ditempuh gajah lalu","makna":"Peribahasa ini menggambarkan kehancuran atau kerusakan yang sangat parah dan tidak dapat diperbaiki lagi, seolah-olah telah dilalui oleh gajah yang besar. Ini melambangkan dampak yang sangat merusak dari suatu peristiwa atau tindakan."},{"peribahasa":"seperti gajah dengan sengkelanya","makna":"Ungkapan ini menggambarkan seseorang yang selalu membawa beban atau masalah yang besar dan tidak dapat dilepaskan. Beban tersebut terus melekat dan menjadi bagian dari dirinya, seperti gajah yang selalu membawa belalainya."},{"peribahasa":"seperti gajah masuk kampung","makna":"Peribahasa ini menggambarkan seseorang yang bertindak ceroboh, tidak sopan, atau tidak tahu aturan di tempat baru, sehingga menimbulkan kekacauan atau kerusakan. Ini adalah sindiran bagi orang yang tidak bisa menyesuaikan diri dengan lingkungan baru."},{"peribahasa":"tebu masuk di mulut gajah","makna":"Ungkapan ini menggambarkan sesuatu yang sangat kecil atau tidak berarti bagi pihak yang besar atau berkuasa. Seberapa pun banyaknya tebu yang diberikan, tidak akan cukup untuk memuaskan gajah, menunjukkan ketidakseimbangan kekuatan atau kebutuhan."},{"peribahasa":"tebu setuntung masuk geraham gajah","makna":"Sama seperti peribahasa sebelumnya, ini menggambarkan sesuatu yang sangat kecil atau tidak berarti bagi pihak yang besar atau berkuasa. Seberapa pun kecilnya tebu, jika masuk ke mulut gajah, tidak akan terasa dampaknya, menunjukkan ketidakseimbangan kekuatan."},{"peribahasa":"terdorong gajah karena besarnya","makna":"Peribahasa ini mengajarkan bahwa seseorang yang memiliki kedudukan tinggi, kekuasaan, atau kekayaan cenderung akan bertindak sesuai dengan statusnya, bahkan jika itu berarti melakukan hal-hal yang besar atau berani. Ini adalah cerminan dari pengaruh status terhadap perilaku."}]');
