insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('24790', 'ga.tal', 'gatal', '', '', '["Adjektiva","Adjektiva","Cakapan","Adjektiva","Cakapan","kiasan","Adjektiva","Cakapan","kiasan"]', '[{"nomor":"1","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"berasa sangat geli yang merangsang pada kulit tubuh (karena kutu dan sebagainya)","contoh":[{"nomor":2,"teks":"kepalaku -- benar karena banyak ketombe"}]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"}],"definisi":"mendatangkan perasaan gatal","contoh":[{"nomor":2,"teks":"ulat bulu itu -- bila tersentuh"}]},{"nomor":"3","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"suka atau ingin bersetubuh (tentang perempuan); gasang","contoh":[{"nomor":2,"teks":"ia dicaci maki, dikatakan perempuan --"}]},{"nomor":"4","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"ingin sekali hendak berbuat sesuatu (memukul dan sebagainya)","contoh":[{"nomor":2,"teks":"tangannya --, hendak meninju kawannya"}]}]', null, '["kegatalan","menggatalkan","segatal"]', '["gatal gusi","gatal mulut","gatal tangan"]', '["bak mandi di air kiambang, pelak lepas gatal pun datang","hati gatal, mata digaruk","kini gatal, besok digaruk","lain gatal, lain digaruk","nyamuk mati, gatal tak lepas","semut gatal gonggong gunung, bagaimana dunia takkan sunyi","siapa gatal, dialah menggaruk","siapa yang gatal, dialah yang menggaruk"]', '[]', '[{"peribahasa":"bak mandi di air kiambang, pelak lepas gatal pun datang","makna":"Peribahasa ini menggambarkan suatu kondisi di mana seseorang merasa tidak nyaman atau gelisah setelah melakukan sesuatu yang tidak benar atau tidak sesuai. Meskipun masalah utama telah berlalu, perasaan tidak enak atau konsekuensi kecil dari perbuatan tersebut masih terus menghantui."},{"peribahasa":"hati gatal, mata digaruk","makna":"Ungkapan ini melukiskan tindakan seseorang yang melampiaskan kekesalan atau kemarahan pada pihak yang tidak bersalah atau tidak relevan. Perasaan tidak nyaman atau gatal di hati justru dilampiaskan dengan menggaruk mata, menunjukkan ketidakmampuan mengelola emosi secara tepat."},{"peribahasa":"kini gatal, besok digaruk","makna":"Peribahasa ini menggambarkan sikap menunda-nunda pekerjaan atau masalah. Sesuatu yang seharusnya segera diselesaikan justru ditunda hingga nanti, yang dapat menyebabkan masalah tersebut semakin membesar atau sulit diatasi."},{"peribahasa":"lain gatal, lain digaruk","makna":"Ungkapan ini melukiskan tindakan seseorang yang tidak tepat sasaran dalam menyelesaikan masalah atau melampiaskan emosi. Masalah yang sebenarnya ada di satu tempat, namun penyelesaian atau pelampiasannya justru dilakukan di tempat lain yang tidak relevan."},{"peribahasa":"nyamuk mati, gatal tak lepas","makna":"Peribahasa ini menggambarkan suatu tindakan yang tidak efektif dalam menyelesaikan masalah. Meskipun penyebab masalah telah dihilangkan (nyamuk mati), dampak atau konsekuensi dari masalah tersebut (gatal) masih tetap ada, menunjukkan bahwa solusi yang diambil tidak tuntas."},{"peribahasa":"semut gatal gonggong gunung, bagaimana dunia takkan sunyi","makna":"Ungkapan ini melukiskan suatu kejadian yang sangat luar biasa atau tidak masuk akal, yang dapat menyebabkan kekacauan atau kegemparan di dunia. Ini adalah metafora untuk peristiwa yang sangat langka dan memiliki dampak besar, sehingga membuat dunia menjadi tidak tenang."},{"peribahasa":"siapa gatal, dialah menggaruk","makna":"Peribahasa ini mengajarkan bahwa setiap orang harus bertanggung jawab atas masalah atau kesulitan yang dihadapinya sendiri. Tidak ada orang lain yang dapat menyelesaikan masalah seseorang kecuali dirinya sendiri, menunjukkan pentingnya kemandirian dan inisiatif."},{"peribahasa":"siapa yang gatal, dialah yang menggaruk","makna":"Sama seperti peribahasa sebelumnya, ini menegaskan bahwa setiap orang harus menyelesaikan masalahnya sendiri. Orang lain tidak dapat merasakan atau memahami sepenuhnya kesulitan yang dialami seseorang, sehingga penyelesaiannya harus datang dari diri sendiri."}]');
