insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('25205', 'ge.lang', 'gelang', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"tumbuhan menjalar, batangnya berair, daunnya kecil berwarna hijau kecokelatan, biasa dimakan sebagai lalap; kerokot〔Portulaca oleracea〕","contoh":[]}]', null, '["tergelang-gelang","bergelang-gelang","gelang-gelang","pergelangan"]', '["gelang laut","gelang bajang","gelang bangle","gelang berpelat","gelang genggam","gelang identifikasi","gelang identitas","gelang incek lado","gelang jengkar","gelang kaku","gelang kana","gelang kano","gelang keroncong","gelang kunci","gelang pelacak","gelang penanda","gelang pilin","gelang pintu","gelang pipa","gelang pontoh","gelang puyuh","gelang rago-rago","gelang rantai","gelang ringgit","gelang sarikit","gelang tasbih","gelang tridatu","gelang untir","gelang kawung","gelang payung","gelang roai"]', '["angkat batang, keluar cacing gelang-gelang","gelang tidak laga sebentuk, laga keduanya","kaki untut dipakaikan gelang"]', '[]', '[{"peribahasa":"angkat batang, keluar cacing gelang-gelang","makna":"Peribahasa ini menggambarkan suatu tindakan yang dilakukan untuk menyelesaikan masalah, namun justru menimbulkan masalah baru yang lebih rumit atau tidak terduga. Ini melukiskan upaya yang tidak efektif dan berujung pada komplikasi yang tidak diinginkan."},{"peribahasa":"gelang tidak laga sebentuk, laga keduanya","makna":"Ungkapan ini berarti bahwa dalam suatu perselisihan atau pertengkaran, tidak ada pihak yang sepenuhnya benar atau salah. Kedua belah pihak memiliki andil dalam konflik tersebut, sehingga keduanya harus bertanggung jawab atas apa yang terjadi."},{"peribahasa":"kaki untut dipakaikan gelang","makna":"Peribahasa ini menggambarkan suatu tindakan yang sia-sia atau tidak tepat guna. Memberikan sesuatu yang berharga atau indah kepada seseorang yang tidak dapat menghargainya atau tidak membutuhkannya, sama seperti memakaikan gelang pada kaki yang bengkak karena penyakit untut."}]');
