insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('25900', 'ge.nap', 'genap', '', '', '["Adjektiva","Adjektiva","Adjektiva"]', '[{"nomor":"1","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"penuh; utuh (tidak kurang); lengkap","contoh":[{"nomor":2,"teks":"perkawinan kita telah -- 32 tahun"}]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"tidak ganjil (tidak gasal) sehingga habis dibagi dua (tentang bilangan)","contoh":[{"nomor":2,"teks":"enam itu bilangan --"}]},{"nomor":"3","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"cocok; pantas","contoh":[{"nomor":2,"teks":"umurnya sudah -- benar untuk dikhitankan"}]}]', null, '["kegenapan","menggenapi","menggenapkan","penggenap","penggenapan","segenap"]', '["genap bulan(nya)"]', '["dibilang genap, dipagar ganjil","keluar tak mengganjilkan, masuk tak menggenapkan (masuk tidak genap, keluar tidak ganjil)","masuk tak genap, keluar tak ganjil","sudah genap bilangannya"]', '[]', '[{"peribahasa":"dibilang genap, dipagar ganjil","makna":"Peribahasa ini menggambarkan suatu keadaan yang tidak konsisten atau tidak sesuai antara perkataan dan perbuatan. Sesuatu yang diucapkan atau direncanakan secara teratur (genap) ternyata dalam pelaksanaannya menjadi tidak teratur atau menyimpang (ganjil)."},{"peribahasa":"keluar tak mengganjilkan, masuk tak menggenapkan (masuk tidak genap, keluar tidak ganjil)","makna":"Ungkapan ini melukiskan seseorang yang kehadirannya atau kepergiannya tidak memberikan dampak signifikan atau tidak mengubah keadaan secara berarti. Ini menunjukkan bahwa individu tersebut tidak memiliki pengaruh yang besar dalam suatu kelompok atau situasi."},{"peribahasa":"masuk tak genap, keluar tak ganjil","makna":"Sama seperti peribahasa sebelumnya, ini menggambarkan seseorang yang tidak memiliki peran atau pengaruh penting dalam suatu kelompok atau situasi. Kehadiran maupun ketidakberadaannya tidak memberikan perbedaan yang berarti, menunjukkan kurangnya kontribusi atau dampak."},{"peribahasa":"sudah genap bilangannya","makna":"Peribahasa ini berarti sudah lengkap atau sudah mencukupi jumlahnya. Ini sering digunakan untuk menyatakan bahwa suatu kelompok atau jumlah telah mencapai batas yang ditentukan atau yang diharapkan."}]');
