insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('26692', 'getah upil', 'getah upil', '', 'getah¹', '[]', '[{"nomor":"1","kelasKata":[],"definisi":"liana yang batangnya bergetah putih, daunnya menjorong dengan ujung sulur berkait, mahkota bunga berwarna kuning pucat dengan pangkal merah, buahnya membulat telur seperti alkesa, tumbuh di bioma tropis basah, tersebar dari Semenanjung Thailand sampai Malesia Barat, getahnya dimanfaatkan untuk karet; ujul〔Willughbeia coriacea〕","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('26682', 'ge.tah', 'getah', '', '', '["Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"zat cair pekat dari batang kayu, buah-buahan, dan sebagainya yang bersifat melekat","contoh":[{"nomor":2,"teks":"-- jarak"},{"nomor":4,"teks":"-- kemboja"},{"nomor":6,"teks":"-- nangka"},{"nomor":8,"teks":"-- sawo"}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"zat cair pekat dari pohon karet (perca)","contoh":[{"nomor":2,"teks":"-- karet mentah sering kali dibuat bola oleh anak-anak"}]}]', null, '["bergetah","getah-getahan","menggetah","penggetahan","pergetahan","tergetah"]', '["getah kelulut","getah keping","getah manggis","getah nyatu","getah padu","getah perca","getah persik","getah pinus","getah purwa","getah susu","getah terap","getah upil","getah bening","getah cerna","getah lambung","getah pankreas"]', '["bagai belut kena ranjau (getah)","bagai getah dibawa ke semak","berleleran bagai getah di lalang","daun dapat dilayangkan, getah jatuh ke perdu juga","getah terbangkit, kuaran tiba","kalau getah meleleh, kalau daun melayang","tak sungguh getah daun, yang sebenarnya getah batang juga","uir-uir minta getah"]', '[]', '[{"peribahasa":"bagai belut kena ranjau (getah)","makna":"Peribahasa ini menggambarkan seseorang yang sangat lincah dan cerdik, namun akhirnya terjebak atau tertangkap karena kelalaian atau kecerobohannya sendiri. Ini melukiskan bahwa seberapa pun lihainya seseorang, pasti ada saatnya ia akan menemui kesulitan atau kegagalan."},{"peribahasa":"bagai getah dibawa ke semak","makna":"Ungkapan ini melukiskan suatu masalah atau urusan yang semakin rumit dan sulit diselesaikan karena dibawa ke tempat yang tidak tepat atau ditangani oleh orang yang tidak kompeten. Ini adalah metafora untuk memperburuk keadaan dengan tindakan yang salah."},{"peribahasa":"berleleran bagai getah di lalang","makna":"Peribahasa ini menggambarkan sesuatu yang tidak rapi, berantakan, atau tidak teratur. Ini melukiskan kondisi yang tidak terkelola dengan baik, sehingga menimbulkan kesan jorok atau tidak profesional."},{"peribahasa":"daun dapat dilayangkan, getah jatuh ke perdu juga","makna":"Ungkapan ini mengajarkan bahwa setiap orang pada akhirnya akan kembali ke asal-usulnya, keluarganya, atau tempat di mana ia seharusnya berada. Ini melambangkan ikatan darah atau asal-usul yang tidak dapat dipisahkan, meskipun seseorang telah pergi jauh atau mencapai kesuksesan."},{"peribahasa":"getah terbangkit, kuaran tiba","makna":"Peribahasa ini menggambarkan suatu kejadian yang terjadi secara bersamaan atau berurutan, di mana satu peristiwa memicu peristiwa lainnya. Ini melukiskan hubungan sebab-akibat atau rentetan kejadian yang saling terkait."},{"peribahasa":"kalau getah meleleh, kalau daun melayang","makna":"Ungkapan ini memiliki makna bahwa setiap orang memiliki takdir atau nasibnya masing-masing. Ada yang ditakdirkan untuk tetap berada di tempat asalnya (getah meleleh), ada pula yang ditakdirkan untuk pergi jauh atau merantau (daun melayang). Ini adalah gambaran dari perbedaan jalan hidup setiap individu."},{"peribahasa":"tak sungguh getah daun, yang sebenarnya getah batang juga","makna":"Peribahasa ini mengajarkan bahwa sesuatu yang tampak dari luar belum tentu mencerminkan kebenaran atau esensi yang sesungguhnya. Ini adalah peringatan untuk tidak mudah tertipu oleh penampilan atau perkataan, melainkan harus mencari tahu substansi yang sebenarnya."},{"peribahasa":"uir-uir minta getah","makna":"Ungkapan ini menggambarkan seseorang yang meminta sesuatu yang tidak mungkin diberikan atau yang tidak sesuai dengan kemampuannya. Ini adalah sindiran bagi orang yang memiliki permintaan yang tidak realistis atau tidak tahu diri."}]');
