insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('27856', 'gu.nung', 'gunung', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bukit yang sangat besar dan tinggi (biasanya tingginya lebih dari 600 m)","contoh":[]}]', '{"text":"[Jawa Kuno gunuṅ ''gunung'']","languages":["Jawa Kuno"]}', '["bergunung","bergunung-gunung","gunung-ganang","gunung-gemunung","gunung-gunungan","gunungan","menggunung","pegunungan","penggunungan","pergunungan","segunung"]', '["Gunung Anjasmoro","gunung api besi","gunung api es","gunung api perisai","Gunung Arjuna","gunung bawah laut","Gunung Bawakaraeng","gunung berapi","Gunung Ciremai","Gunung Dempo","gunung es","Gunung Everest","Gunung Galunggung","Gunung Gamalama","Gunung Gamkonora","Gunung Gede","Gunung Guntur","Gunung Halimun","gunung Ineilika","gunung istirahat","Gunung Karang","Gunung Kawi","Gunung Kelam","Gunung Kelimutu","Gunung Kelud","gunung kembar","Gunung Lakaan","Gunung Latimojong","Gunung Lewotolo","Gunung Lokon","gunung lumpur","Gunung Manglayang","gunung mati","Gunung Mekongga","Gunung Merapi","Gunung Padang","Gunung Pangrango","gunung pasir","Gunung Patuha","Gunung Penanggungan","Gunung Pesagi","Gunung Pesawaran","Gunung Prau","Gunung Pulosari","gunung purba","Gunung Putri","Gunung Rajabasa","Gunung Raung","Gunung Rinjani","Gunung Sago","Gunung Salak","Gunung Sanggabuana","Gunung Sanggar","Gunung Seblat","Gunung Semeru","Gunung Seminung","Gunung Sibayak","Gunung Sibela","Gunung Sinabung","Gunung Singgalang","Gunung Sipahabuabu","Gunung Slamet","gunung sulah","Gunung Sumbing","Gunung Sunda","Gunung Sunda Purba","Gunung Tambora","Gunung Tangkuban Perahu","Gunung Welirang","Pakuwaja","Sindoro"]', '["ada jalan ke puncak gunung yang tinggi","adat gunung tempatan kabut, adat teluk timbunan kapal (kapar)","asam di darat, ikan di laut (garam di laut asam di gunung) bertemu dalam belanga","garam di laut, asam di gunung bertemu dalam belanga juga","gunung juga yang dilejang panas","ikan di laut, asam di gunung, bertemu dalam belanga","ke gunung tak dapat angin","maksud hati memeluk gunung, apa daya tangan tak sampai","masakan gunung akan runtuh walaupun seribu anjing menyalak","menambak gunung, menggarami air laut","menambak gunung, menggarami laut","rendah gunung, tinggi harapan","sekepal menjadi gunung, setitik menjadi laut","semut gatal gonggong gunung, bagaimana dunia takkan sunyi","tak akan (takkan) lari gunung dikejar, hilang kabut tampaklah dia","tak kan lari gunung dikejar, hilang kabut tampaklah dia","telaga di bawah gunung","tuah melambung tinggi, celaka menimpa, celaka sebesar gunung"]', '[]', '[{"peribahasa":"ada jalan ke puncak gunung yang tinggi","makna":"Peribahasa ini mengajarkan bahwa setiap tujuan yang sulit atau ambisi yang besar pasti memiliki cara atau jalan untuk mencapainya, meskipun mungkin memerlukan usaha dan ketekunan yang luar biasa. Ini adalah ungkapan optimisme dan dorongan untuk tidak menyerah pada kesulitan."},{"peribahasa":"adat gunung tempatan kabut, adat teluk timbunan kapal (kapar)","makna":"Ungkapan ini menggambarkan bahwa setiap tempat atau lingkungan memiliki karakteristik dan kebiasaan alaminya sendiri. Gunung selalu diselimuti kabut, dan teluk selalu menjadi tempat berkumpulnya kapal. Ini melambangkan bahwa setiap hal memiliki takdir atau sifat yang melekat padanya."},{"peribahasa":"asam di darat, ikan di laut (garam di laut asam di gunung) bertemu dalam belanga","makna":"Peribahasa ini menggambarkan bahwa meskipun dua individu atau kelompok memiliki latar belakang, asal, atau sifat yang sangat berbeda, pada akhirnya mereka akan bertemu dan bersatu karena takdir atau kesamaan tujuan. Ini melambangkan jodoh atau persatuan yang tidak terduga."},{"peribahasa":"garam di laut, asam di gunung bertemu dalam belanga juga","makna":"Sama seperti peribahasa sebelumnya, ini menegaskan bahwa meskipun dua individu atau kelompok memiliki latar belakang yang sangat berbeda dan terpisah jauh, pada akhirnya mereka akan bersatu atau berjodoh. Ini adalah metafora untuk takdir yang mempertemukan dua insan."},{"peribahasa":"gunung juga yang dilejang panas","makna":"Peribahasa ini menggambarkan bahwa orang yang memiliki kedudukan tinggi, kekuasaan, atau kekayaan seringkali menjadi sasaran utama dari berbagai masalah, kritik, atau serangan. Ini melukiskan bahwa semakin tinggi posisi seseorang, semakin besar pula tantangan dan risiko yang dihadapinya."},{"peribahasa":"ikan di laut, asam di gunung, bertemu dalam belanga","makna":"Sama seperti peribahasa tentang asam dan garam, ini menegaskan bahwa meskipun dua individu atau kelompok memiliki latar belakang yang sangat berbeda dan terpisah jauh, pada akhirnya mereka akan bersatu atau berjodoh. Ini adalah metafora untuk takdir yang mempertemukan dua insan."},{"peribahasa":"ke gunung tak dapat angin","makna":"Ungkapan ini menggambarkan suatu usaha yang sia-sia atau tidak membuahkan hasil, meskipun telah dilakukan dengan susah payah. Ini melukiskan kekecewaan karena tidak mendapatkan apa yang diharapkan, meskipun telah berjuang keras."},{"peribahasa":"maksud hati memeluk gunung, apa daya tangan tak sampai","makna":"Peribahasa ini menggambarkan keinginan atau cita-cita yang sangat besar dan mulia, namun tidak dapat tercapai karena keterbatasan kemampuan, sarana, atau kesempatan. Ini melukiskan kesenjangan antara ambisi dan realitas."},{"peribahasa":"masakan gunung akan runtuh walaupun seribu anjing menyalak","makna":"Ungkapan ini mengajarkan bahwa sesuatu yang besar, kokoh, atau memiliki kedudukan yang kuat tidak akan mudah goyah atau hancur hanya karena gangguan kecil atau kritik yang tidak berarti. Ini melambangkan ketahanan dan stabilitas yang tidak terpengaruh oleh hal-hal remeh."},{"peribahasa":"menambak gunung, menggarami air laut","makna":"Peribahasa ini menggambarkan suatu perbuatan yang sia-sia atau tidak ada gunanya. Melakukan sesuatu yang tidak memberikan dampak atau manfaat sama sekali, seperti menambak gunung yang sudah besar atau menggarami laut yang sudah asin, menunjukkan ketidakefisienan atau pemborosan."},{"peribahasa":"menambak gunung, menggarami laut","makna":"Sama seperti peribahasa sebelumnya, ini menegaskan bahwa melakukan sesuatu yang tidak memberikan dampak atau manfaat sama sekali adalah perbuatan yang sia-sia. Ini adalah kritik terhadap tindakan yang tidak efektif atau tidak relevan."},{"peribahasa":"rendah gunung, tinggi harapan","makna":"Ungkapan ini menggambarkan bahwa meskipun seseorang memiliki kedudukan atau status yang rendah, ia memiliki cita-cita, impian, atau harapan yang sangat besar. Ini melukiskan semangat juang dan optimisme yang tidak terbatas oleh keterbatasan fisik atau sosial."},{"peribahasa":"sekepal menjadi gunung, setitik menjadi laut","makna":"Peribahasa ini menggambarkan bahwa sesuatu yang kecil atau sedikit, jika dikumpulkan atau dilakukan secara terus-menerus, dapat menjadi sangat besar atau banyak. Ini mengajarkan pentingnya ketekunan, kesabaran, dan akumulasi dalam mencapai tujuan besar."},{"peribahasa":"semut gatal gonggong gunung, bagaimana dunia takkan sunyi","makna":"Ungkapan ini melukiskan suatu kejadian yang sangat luar biasa atau tidak masuk akal, yang dapat menyebabkan kekacauan atau kegemparan di dunia. Ini adalah metafora untuk peristiwa yang sangat langka dan memiliki dampak besar, sehingga membuat dunia menjadi tidak tenang."},{"peribahasa":"tak akan (takkan) lari gunung dikejar, hilang kabut tampaklah dia","makna":"Peribahasa ini mengajarkan bahwa sesuatu yang sudah pasti atau sudah menjadi takdir tidak perlu dikejar-kejar atau dikhawatirkan secara berlebihan. Pada waktunya, kebenaran atau hasil dari suatu peristiwa akan terungkap dengan sendirinya, seperti gunung yang akan terlihat setelah kabut menghilang."},{"peribahasa":"tak kan lari gunung dikejar, hilang kabut tampaklah dia","makna":"Sama seperti peribahasa sebelumnya, ini menegaskan bahwa sesuatu yang sudah pasti atau sudah menjadi takdir tidak perlu dikejar-kejar atau dikhawatirkan secara berlebihan. Pada waktunya, kebenaran atau hasil dari suatu peristiwa akan terungkap dengan sendirinya, seperti gunung yang akan terlihat setelah kabut menghilang."},{"peribahasa":"telaga di bawah gunung","makna":"Ungkapan ini menggambarkan seseorang yang memiliki pengetahuan, kekayaan, atau sumber daya yang melimpah, namun tidak suka memamerkannya. Ia adalah pribadi yang rendah hati, meskipun memiliki potensi yang besar, seperti telaga yang tersembunyi di bawah gunung."},{"peribahasa":"tuah melambung tinggi, celaka menimpa, celaka sebesar gunung","makna":"Peribahasa ini menggambarkan bahwa keberuntungan atau kesuksesan yang besar seringkali diikuti oleh kemalangan atau musibah yang tidak kalah besar. Ini adalah peringatan untuk selalu waspada dan tidak terlena dengan kesuksesan, karena nasib buruk bisa datang kapan saja."}]');
