insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('27925', 'gu.ru', 'guru', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"orang yang pekerjaannya (mata pencahariannya, profesinya) mengajar","contoh":[]}]', null, '["berguru","keguruan","menggurui","pengguruan","perguruan","seperguruan"]', '["guru agama","guru alif","guru angkat","guru baku","guru bantu","guru bayang","guru besar","guru dalam jabatan","guru daljab","guru honorer","guru inval","guru kelas","guru kepala","guru kula","guru lagu","guru mata pelajaran","guru mengaji","guru pamong","guru pembimbing","guru pendamping","guru penggerak","guru penolong","guru praktikan","guru privat","guru profesional","guru pustakawan","guru sekolah","guru spiritual","guru suara","guru tamu","guru tetap","guru tulang","guru wilangan","guru wiyata bakti"]', '["guru kencing berdiri, murid kencing berlari","kalau guru makan berdiri, maka murid makan berlari"]', '[]', '[{"peribahasa":"guru kencing berdiri, murid kencing berlari","makna":"Peribahasa ini mengajarkan bahwa perilaku seorang pemimpin atau guru akan dicontoh oleh pengikut atau muridnya. Jika seorang pemimpin melakukan hal yang tidak baik, maka pengikutnya cenderung akan melakukan hal yang lebih buruk. Ini menekankan pentingnya keteladanan dari seorang pemimpin."},{"peribahasa":"kalau guru makan berdiri, maka murid makan berlari","makna":"Sama seperti peribahasa sebelumnya, ini menegaskan bahwa perilaku seorang pemimpin atau guru akan dicontoh oleh pengikut atau muridnya. Jika seorang pemimpin melakukan hal yang tidak baik, maka pengikutnya cenderung akan melakukan hal yang lebih buruk. Ini menekankan pentingnya keteladanan dari seorang pemimpin."}]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('27948', 'gu.rub', 'gurub', '', '', '["Verba","Arab"]', '[{"nomor":"1","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"},{"kode":"Ar","nama":"Arab","tipe":"lainnya"}],"definisi":"hilang; jatuh; runtuh; tenggelam","contoh":[]}]', '{"text":"[Arab غُرُوْبٌ gurūb n sg m ''tenggelam'']","languages":["Arab"]}', '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('27949', 'gu.ruh', 'guruh', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"suara menggelegar di udara (disebabkan oleh halilintar); guntur","contoh":[]}]', '{"text":"[Jawa Kuno guruh ''guruh'']","languages":["Jawa Kuno"]}', '["gemuruh","mengguruh"]', '[]', '["harapkan guruh (guntur) di langit, air di tempayan ditumpahkan","hari guruh takkan hujan","serba guruh serba putus","tak ada guruh bagi orang pekak, tak ada kilat bagi orang buta"]', '[]', '[{"peribahasa":"harapkan guruh (guntur) di langit, air di tempayan ditumpahkan","makna":"Peribahasa ini mengajarkan bahwa seseorang tidak boleh terlalu berharap pada sesuatu yang belum pasti atau yang masih jauh di masa depan, sehingga mengabaikan apa yang sudah ada di tangan. Ini adalah peringatan untuk tidak melepaskan yang sudah pasti demi mengejar yang belum jelas, yang dapat berujung pada kerugian."},{"peribahasa":"hari guruh takkan hujan","makna":"Ungkapan ini berarti bahwa ancaman atau gertakan yang keras (guruh) belum tentu akan diikuti dengan tindakan nyata atau konsekuensi yang serius (hujan). Ini adalah sindiran bagi orang yang banyak bicara tetapi tidak berani bertindak."},{"peribahasa":"serba guruh serba putus","makna":"Peribahasa ini menggambarkan bahwa segala sesuatu yang dilakukan dengan tergesa-gesa, tanpa perhitungan, atau dengan emosi yang meledak-ledak, cenderung akan berakhir dengan kegagalan atau kerusakan. Ini adalah peringatan untuk bertindak dengan hati-hati dan penuh pertimbangan."},{"peribahasa":"tak ada guruh bagi orang pekak, tak ada kilat bagi orang buta","makna":"Ungkapan ini mengajarkan bahwa seseorang tidak akan dapat memahami atau merasakan sesuatu jika ia tidak memiliki kemampuan atau indra yang diperlukan. Ini adalah metafora untuk keterbatasan pemahaman atau pengalaman seseorang terhadap hal-hal yang berada di luar jangkauannya."}]');
