insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('27954', 'gu.run', 'gurun', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"padang luas yang tandus; padang pasir","contoh":[]}]', null, '["penggurunan"]', '["gurun angin pasat","gurun arktik","gurun batu","gurun kutub","gurun pasir","gurun tandus"]', '["jika tak lalu dandang di air, di gurun dirangkakkan (ditanjakkan)","menaikkan air ke gurun"]', '[]', '[{"peribahasa":"jika tak lalu dandang di air, di gurun dirangkakkan (ditanjakkan)","makna":"Peribahasa ini mengajarkan bahwa jika suatu usaha atau cara tidak berhasil di satu tempat atau dengan satu metode, maka harus dicari cara lain atau tempat lain yang mungkin lebih sesuai. Ini melambangkan kegigihan dan adaptabilitas dalam menghadapi tantangan, serta pentingnya mencari solusi alternatif ketika menghadapi hambatan."},{"peribahasa":"menaikkan air ke gurun","makna":"Ungkapan ini melukiskan suatu perbuatan yang sia-sia atau tidak ada gunanya. Melakukan sesuatu yang tidak memberikan dampak atau manfaat sama sekali, seperti mencoba membawa air ke gurun yang sudah kering, menunjukkan ketidakefisienan atau pemborosan sumber daya."}]');
